function sum(n) {
  // ベースケース: nが1の場合は1を返す
  if(n === 1) return 1;
  // 再帰ステップ: n + sum(n - 1)を返す
  return n + sum(n - 1);
}
console.log(sum(5));
// 15が出力されます。

function sumOddNumbers(n) {
  // 奇数の和を保存するための変数
  let sum = 0;
  // 1からnまでループ
  for(let i = 1; i <= n; i++) {
    // 奇数だけを加算
    if(i % 2 !== 0) sum += i;
  }
  return sum;
}
console.log(sumOddNumbers(10));
// 出力: 25 (1 + 3 + 5 + 7 + 9)

function sumMatrix(matrix) {
  // 合計を保存するための変数
  let sum = 0;
  // 配列の各行をループ
  for(let i = 0; i < matrix.length; i++) {
    // 各行の各要素をループ
    for(let j = 0; j < matrix[i].length; j++) {
      // 要素を合計に加算
      sum += matrix[i][j];
    }
  }
  return sum;
}
console.log(sumMatrix([[1, 2, 3], [4, 5, 6], [7, 8, 9]]));
// 出力: 45

function doubleNumbers(arr) {
  // mapメソッドで配列の全ての要素を2倍にする
  return arr.map(function(num) {
    // 各要素を2倍にして返す
    return num * 2;
  });
}
console.log(doubleNumbers([1, 2, 3, 4, 5]));
// 出力: [2, 4, 6, 8, 10]

function sumNestedArrays(arr) {
  // mapメソッドで二次元配列の各サブ配列に対して処理を行う
  return arr.map(function(subArr) {
    // reduceメソッドでサブ配列の全ての要素を足し合わせる
    return subArr.reduce(function(sum, num) {
      // 各要素を合計値に加える
      return sum + num;
    }, 0);
  });
}
console.log(sumNestedArrays([[1, 2, 3], [4, 5, 6], [7, 8, 9]]));
// 出力: [6, 15, 24]

function printKeyValue(obj) {
  // for...inループでオブジェクトの全てのプロパティに対して処理を行う
  for (var key in obj) {
    // キーとその値を表示する
    console.log('Key: ' + key + ', Value: ' + obj[key]);
  }
}
printKeyValue({name: 'Alice', age: 25, country: 'Japan'});
// 出力: 
// Key: name, Value: Alice
// Key: age, Value: 25
// Key: country, Value: Japan

function print2DArray(arr) {
  // 外側のループ：各"行"を処理する
  for (var i = 0; i < arr.length; i++) {
    // 内側のループ：各"列"を処理する
    for (var j = 0; j < arr[i].length; j++) {
      // それぞれの要素を表示する
      console.log('Element [' + i + '][' + j + ']: ' + arr[i][j]);
