function repeatString(str, num) {
  // 繰り返す文字列を格納する変数を初期化します。
  let repeatedStr = '';
  // 指定した回数だけループします。
  for (let i = 0; i < num; i++) {
    // 繰り返す文字列を追加します。
    repeatedStr += str;
  }
  // 繰り返し文字列を出力します。
  console.log(repeatedStr);
}

// 関数をテストします。
repeatString('Hello', 3);
// 出力：HelloHelloHello

